mkdir -p /tmp/sv-6a9de9bfb171477b8317213d30b9a478/typed-meta && cd /tmp/sv-6a9de9bfb171477b8317213d30b9a478/typed-meta && dotnet new console --framework net11.0 -o . --force -n TypedMeta > /dev/null 2>&1 && cat > Program.cs << 'EOF'
using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

// Set up options with the default reflection-based resolver
var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// 1) Strongly-typed retrieval: returns JsonTypeInfo<Person> directly
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Got typed metadata for: {personInfo.Type.Name}");

// 2) Probe without throwing — TryGetTypeInfo returns false if unavailable
//    Here we try a type the resolver *can* handle:
if (options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? info))
    Console.WriteLine($"TryGetTypeInfo succeeded for Person (kind: {info!.Kind})");
else
    Console.WriteLine("TryGetTypeInfo: Person metadata NOT available");

// Now try with an empty resolver that resolves nothing:
var limited = new JsonSerializerOptions
{
    TypeInfoResolver = new EmptyResolver()
};

if (limited.TryGetTypeInfo(typeof(Person), out _))
    Console.WriteLine("TryGetTypeInfo succeeded for Person on limited resolver");
else
    Console.WriteLine("TryGetTypeInfo: Person metadata NOT available (expected)");

// --- Types ---

record Person(string Name, int Age);

// A resolver that never provides metadata for any type
sealed class EmptyResolver : IJsonTypeInfoResolver
{
    public JsonTypeInfo? GetTypeInfo(Type type, JsonSerializerOptions options) => null;
}
EOF

